+func TestResolveSwarmInitialPrompt_PromptFlag(t *testing.T) {
+	got, source, path, err := resolveSwarmInitialPrompt("hello", "")
+	if err != nil {
+		t.Fatalf("resolveSwarmInitialPrompt error: %v", err)
+	}
+	if got != "hello" {
